eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   questions: () => (/* binding */ questions)\n/* harmony export */ });\nconst questions = [\n    {\n        \"id\": 1,\n        \"text\": \"Average age of A, B and C is 30 years. The sum of the present ages of B and C is 85 years. The difference between the present age of A and C is 50 years. Find the average age of B and C together?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"40.5 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"41.5 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"42.5 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"43.5 years\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"Average age of A, B and C = 30\\nA+B+C = 90\\nSum of the present age of B and C = 85\\nSo, A = 90 - 85 = 5 years\\nDifference between the present age of A and C = 50\\nC - A = 50 => C - 5 = 50 => C = 55\\nThe present age of B = 85 - 55 = 30 years\\nAverage age of B and C = (55 + 30)/2 = 85/2 = 42.5 years\"\n    },\n    {\n        \"id\": 2,\n        \"text\": \"The present ages of mother and son are 28 and 7 years respectively. If the ratio of their ages will be 11 : 4 after x years, then find the value of x?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"5\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"4\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"6\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"8\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"According to the question,\\n(28 + x) / (7 + x) = 11 / 4\\n4(28 + x) = 11(7 + x)\\n112 + 4x = 77 + 11x\\n112 - 77 = 11x - 4x\\n35 = 7x\\nx = 5\"\n    },\n    {\n        \"id\": 3,\n        \"text\": \"The average age of 3 midfield players is 27 years. If one of the midfield players age is 25 years, then find the average age of other two midfield players.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"26\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"28\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"30\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"25\"\n            }\n        ],\n        \"answer\": \"B\",\n        \"explanation\": \"Average age of 3 midfield players = 27\\nSum of 3 midfield players age = 27 * 3 = 81\\nSum of other two midfield players age = 81 – 25 = 56\\nRequired average = 56 / 2 = 28\"\n    },\n    {\n        \"id\": 4,\n        \"text\": \"3 years ago, the ratio of the age of A to B is 3:4. The present age of C is 33.33% more than that of A and the sum of the present age of B and C together is 71 years. Find the difference between the present age of A and B.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"8 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"6 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"9 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"5 years\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"Let the present age of A = 3x + 3\\nAnd the present age of B = 4x + 3\\nC = A + 33.33% of A = A * (4/3)\\nPresent age of B + Present age of C = 71\\n(4x + 3) + (3x + 3) * (4/3) = 71\\n4x + 3 + 4x + 4 = 71\\n8x + 7 = 71\\n8x = 64\\nx = 8\\nThe present age of A = 3 * 8 + 3 = 27 years\\nThe present age of B = 4 * 8 + 3 = 35 years\\nRequired difference = 35 – 27 = 8 years\"\n    },\n    {\n        \"id\": 5,\n        \"text\": \"Find the difference between the ages of Aman and Amit, 10 years ago. The ratio of ages of Amit and Aman after 8 years will be 12: 11 respectively. 4 years ago, Arav’s age was 62.5% of Aman’s age at that time. Arav is the youngest and Amit is the eldest among three friends. The difference in the ages of Arav and Amit is 16 years.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"6 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"5 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"8 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"4 years\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"Let present ages of Amit, Aman and Arav be Amit, Aman and Arav.\\n(Amit + 8) / (Aman + 8) = 12 / 11 => 11Amit - 12Aman = 8 ... (1)\\n(Arav - 4) = 62.5% of (Aman - 4) => (Arav - 4) / (Aman - 4) = 5 / 8 => 8Arav - 5Aman = 12 ... (2)\\nAmit - Arav = 16 => Arav = Amit - 16\\nSubstitute Arav in (2): 8(Amit - 16) - 5Aman = 12 => 8Amit - 128 - 5Aman = 12 => 8Amit - 5Aman = 140 ... (3)\\nSolving (1) and (3):\\nAmit = 40, Aman = 36, Arav = 24\\nAge of Aman - age of Amit = 36 - 40 = -4. Difference = 4 years.\\n10 years ago difference remains same. Ans = 4 years.\"\n    },\n    {\n        \"id\": 6,\n        \"text\": \"The age of Mathi is 120% of the age of Sunil and the ratio of the age of Sunil to Bala is 5:8. If the age of Mathi 5 years hence is equal to the age of Bala 5 years ago, then find the age of Sunil?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"25 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"50 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"20 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"30 years\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"Mathi : Sunil = 120 : 100 = 6 : 5\\nSunil : Bala = 5 : 8\\nSo, Mathi : Sunil : Bala = 6 : 5 : 8\\nLet their ages be 6x, 5x, 8x.\\n6x + 5 = 8x – 5\\n2x = 10 => x = 5\\nThe age of Sunil = 5 * 5 = 25 years\"\n    },\n    {\n        \"id\": 7,\n        \"text\": \"The age of father before 18 years is 2 years more than 140% of the present age of son. Ratio of the age of father before 8 years to the present age of son is 2:1. Find the average of the present age of father and son.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"28 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"34 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"30 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"35 years\"\n            }\n        ],\n        \"answer\": \"B\",\n        \"explanation\": \"Let present age of son = x\\nFather - 8 / x = 2 / 1 => Father = 2x + 8\\nBefore 18 years, Father's age = 2x + 8 - 18 = 2x - 10\\nAccording to the question:\\n2x - 10 = (140/100) * x + 2\\n2x - 12 = 1.4x\\n0.6x = 12 => x = 20\\nSon = 20, Father = 2(20) + 8 = 48\\nAverage = (48 + 20) / 2 = 34 years\"\n    },\n    {\n        \"id\": 8,\n        \"text\": \"The ratio of the age of A 5 years ago to the age of B 4 years hence is 2:5 and the ratio of the present age of B to A is 12:7. Find the sum of the present age of A and B together.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"39 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"65 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"57 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"45 years\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"Let present ages of A and B be 7x and 12x.\\n(7x - 5) / (12x + 4) = 2 / 5\\n35x - 25 = 24x + 8\\n11x = 33 => x = 3\\nA = 7(3) = 21, B = 12(3) = 36\\nSum = 21 + 36 = 57 years\"\n    },\n    {\n        \"id\": 9,\n        \"text\": \"The sum of present age of A and B is 5/3rd of the present age of C and the ratio of the age of A to C is 10:9. If the sum of the present age of B and C together is 28 years, then find the present age of A.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"40 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"10 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"30 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"20 years\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"A : C = 10 : 9. Let A = 10x, C = 9x.\\nA + B = (5/3) * C = (5/3) * 9x = 15x\\nB = 15x - 10x = 5x\\nB + C = 28 => 5x + 9x = 28 => 14x = 28 => x = 2\\nA = 10 * 2 = 20 years\"\n    },\n    {\n        \"id\": 10,\n        \"text\": \"4 years ago, the ratio of the age of A to B is 11:3. If the present age of A is two times more than the present age of B, then find the age of B 10 years hence.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"42 years\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"30 years\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"55 years\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"26 years\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"4 years ago, A = 11x, B = 3x. Present ages: A = 11x + 4, B = 3x + 4.\\nPresent A is two times MORE than B => A = B + 2B = 3B\\n11x + 4 = 3(3x + 4)\\n11x + 4 = 9x + 12\\n2x = 8 => x = 4\\nPresent B = 3(4) + 4 = 16\\nB after 10 years = 16 + 10 = 26 years\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./data/aptitude/ages.js\n");

