"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   questions: () => (/* binding */ questions)\n/* harmony export */ });\nconst questions = [\n    {\n        \"id\": 1,\n        \"text\": \"How many perfect squares lie between 120 and 300?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"5\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"6\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"7\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"8\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"Perfect squares between 120 and 300 are:\\n11\\xb2 = 121\\n12\\xb2 = 144\\n13\\xb2 = 169\\n14\\xb2 = 196\\n15\\xb2 = 225\\n16\\xb2 = 256\\n17\\xb2 = 289\\nTotal count = 7.\"\n    },\n    {\n        \"id\": 2,\n        \"text\": \"What smallest number must be added to 710 so that the sum is a perfect cube?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"11\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"14\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"19\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"21\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"The closest perfect cube greater than 710 is 9\\xb3 = 729.\\nRequired number to be added = 729 - 710 = 19.\"\n    },\n    {\n        \"id\": 3,\n        \"text\": \"The smallest natural number which is a perfect square and which ends in 3 identical digits lies between:\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"1000 and 2000\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"2000 and 3000\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"3000 and 4000\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"4000 and 5000\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"The smallest such number is 1444 [= (38)\\xb2]. It ends in three '4's and lies between 1000 and 2000.\"\n    },\n    {\n        \"id\": 4,\n        \"text\": \"The largest four digit number which is a perfect cube is:\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"7000\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"8000\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"9261\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"9999\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"21\\xb3 = 9261\\n22\\xb3 = 10648 (Five digits)\\nSo, 9261 is the largest four-digit perfect cube.\"\n    },\n    {\n        \"id\": 5,\n        \"text\": \"The least number by which 294 must be multiplied to make it a perfect square is:\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"2\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"3\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"4\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"6\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"294 = 2 * 147 = 2 * 3 * 49 = 2 * 3 * 7 * 7.\\nTo be a perfect square, each prime factor must have an even power.\\n2 and 3 have power 1, so multiply by 2 * 3 = 6.\"\n    },\n    {\n        \"id\": 6,\n        \"text\": \"What is the smallest number by which 3600 must be divided to make it a perfect cube?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"50\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"250\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"450\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"500\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"3600 = 36 * 100 = 6\\xb2 * 10\\xb2 = (2*3)\\xb2 * (2*5)\\xb2 = 2⁴ * 3\\xb2 * 5\\xb2.\\nTo make it a cube, we group into cubes: 2\\xb3 * (2\\xb9 * 3\\xb2 * 5\\xb2).\\nDivide by the extra factors: 2 * 9 * 25 = 450.\"\n    },\n    {\n        \"id\": 7,\n        \"text\": \"1250 oranges were distributed among a group of girls. Each girl got twice as many oranges as the number of girls. Find the number of girls.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"25\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"35\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"45\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"65\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"Let number of girls = x.\\nEach girl gets 2x oranges.\\nTotal = x * 2x = 1250 => 2x\\xb2 = 1250 => x\\xb2 = 625 => x = 25.\"\n    },\n    {\n        \"id\": 8,\n        \"text\": \"Find the smallest number by which 5808 should be multiplied so that the product becomes a perfect square.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"1\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"2\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"3\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"5\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"5808 = 2⁴ * 3 * 11\\xb2.\\nTo balance the powers (all should be even), multiply by 3.\"\n    },\n    {\n        \"id\": 9,\n        \"text\": \"A company pays the team per run as much as the total runs. Which cannot be the total amount spent (must be a perfect square)?\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"21,904\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"56,169\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"1,01,761\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"1,21,108\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"A perfect square cannot end in digits 2, 3, 7, or 8. Option D ends in 8.\"\n    },\n    {\n        \"id\": 10,\n        \"text\": \"The smallest perfect square that is divisible by 7! is:\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"19600\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"44100\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"176400\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"705600\"\n            }\n        ],\n        \"answer\": \"C\",\n        \"explanation\": \"7! = 5040 = 2⁴ * 3\\xb2 * 5 * 7.\\nTo make it a square, multiply by factors with odd powers (5 and 7).\\nSmallest square = 5040 * 5 * 7 = 176400.\"\n    },\n    {\n        \"id\": 11,\n        \"text\": \"A man born in the first half of the 19th century was x years old in the year x\\xb2. He was born in:\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"1806\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"1812\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"1825\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"1836\"\n            }\n        ],\n        \"answer\": \"A\",\n        \"explanation\": \"Year x\\xb2 in the 19th century: 43\\xb2 = 1849.\\nAge x = 43.\\nBirth Year = 1849 - 43 = 1806.\"\n    },\n    {\n        \"id\": 12,\n        \"text\": \"Find x if (15)\\xb2 + (18)\\xb2 - 20 = √x.\",\n        \"options\": [\n            {\n                \"id\": \"A\",\n                \"text\": \"22\"\n            },\n            {\n                \"id\": \"B\",\n                \"text\": \"23\"\n            },\n            {\n                \"id\": \"C\",\n                \"text\": \"x = 529\"\n            },\n            {\n                \"id\": \"D\",\n                \"text\": \"279841\"\n            }\n        ],\n        \"answer\": \"D\",\n        \"explanation\": \"√x = 225 + 324 - 20 = 529.\\nx = 529\\xb2 = 279841.\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./data/aptitude/square-roots-and-cube-roots.js\n");

